// Getters are only allowed inside structs (not enums). For deserialization,
// getters are only supported with the `remote` attribute.
fn check_getter(cx: &Ctxt, cont: &Container, derive: Derive) {
    match cont.data {
        Data::Enum(_) => {
            if cont.data.has_getter() {
                cx.error_spanned_by(
                    cont.original,
                    "#[serde(getter = \"...\")] is not allowed in an enum",
                );
            }
        }
        Data::Struct(_, _) => {
            if derive == Derive::Deserialize
                && cont.data.has_getter()
                && cont.attrs.remote().is_none()
            {
                cx.error_spanned_by(
                    cont.original,
                    "#[serde(getter = \"...\")] can only be used in structs that have #[serde(remote = \"...\")] when deserializing",
                );
            }
        }
    }
}

